### Refactored Example (incorporating key fixes)

```javascript
const express = require('express');
const crypto = require('crypto');
const Joi = require('joi'); // For input validation
const app = express();

// --- Configuration ---
const WEBHOOK_SECRET = process.env.WEBHOOK_SECRET || 'your-super-secret-key'; // Store securely!
const PORT = process.env.PORT || 3000;

// --- Webhook Event Schema (Example) ---
const eventSchema = Joi.object({
    id: Joi.string().guid({ version: 'uuidv4' }).required(), // Assuming UUIDs
    type: Joi.string().valid('user.created', 'order.paid', 'item.deleted', 'error_trigger').required(),
    data: Joi.object().required(), // Further validate 'data' object as needed
    timestamp: Joi.number().integer().min(0).required(),
    // Add any other fields expected from your webhook provider
});

// --- Mock Event Processor (Simulates async work and potential errors) ---
async function processEvent(event) {
    console.log(`[${new Date().toISOString()}] Processing event: ${event.type} (ID: ${event.id})`);
    // Simulate some asynchronous work
    await new Promise(resolve => setTimeout(resolve, Math.random() * 500 + 100)); // 100-600ms delay

    // Simulate an error based on event type for testing
    if (event.type === 'error_trigger') {
        throw new Error('Simulated processing error for error_trigger event.');
    }

    // Simulate idempotency check (simplified)
    // In a real app, you'd check a database for event.id
    if (event.data.processed_before) {
        console.warn(`[${new Date().toISOString()}] Event ${event.id} already processed. Skipping.`);
        return { status: 'skipped', message: 'Event already processed.' };
    }

    console.log(`[${new Date().toISOString()}] Event ${event.id} processed successfully.`);
    return { status: 'success', message: 'Event processed.' };
}

// --- Middleware to capture raw body for signature verification ---
// This must come *before* express.json() for the webhook route
app.use('/api/webhook', express.raw({ type: 'application/json', limit: '1mb' }));

// --- Middleware to parse JSON body (after raw body capture) ---
app.use('/api/webhook', (req, res, next) => {
    if (req.body && req.headers['content-type'] === 'application/json') {
        req.rawBody = req.body.toString('utf8'); // Store raw body for verification
        try {
            req.body = JSON.parse(req.rawBody); // Parse for the handler
        } catch (e) {
            console.error(`[${new Date().toISOString()}] Failed to parse JSON after raw body capture:`, e.message);
            return res.status(400).json({ error: 'Invalid JSON payload' });
        }
    }
    next();
});

// --- Webhook Endpoint ---
app.post('/api/webhook', async (req, res, next) => {
    console.log(`[${new Date().toISOString()}] Webhook received from ${req.ip}`);

    // 1. Webhook Signature Verification (CRITICAL)
    const signature = req.headers['x-hub-signature-256'] || req.headers['x-signature']; // Adjust header name as per provider
    const rawBody = req.rawBody; // Captured by custom middleware

    if (!signature || !rawBody) {
        console.warn(`[${new Date().toISOString()}] Missing signature or raw body for webhook verification.`);
        return res.status(400).json({ error: 'Bad Request: Missing signature or raw body.' });
    }

    try {
        const hmac = crypto.createHmac('sha256', WEBHOOK_SECRET);
        hmac.update(rawBody);
        const expectedSignature = `sha256=${hmac.digest('hex')}`; // Adjust format if needed (e.g., just the hex)

        if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expectedSignature))) {
            console.warn(`[${new Date().toISOString()}] Webhook signature mismatch! Received: ${signature}, Expected: ${expectedSignature}`);
            return res.status(401).json({ error: 'Unauthorized: Invalid signature.' });
        }
        console.log(`[${new Date().toISOString()}] Webhook signature verified successfully.`);
    } catch (sigError) {
        console.error(`[${new Date().toISOString()}] Error during signature verification:`, sigError.message);
        return res.status(500).json({ error: 'Internal Server Error during signature verification.' });
    }

    // 2. Input Validation
    const { error, value: event } = eventSchema.validate(req.body, { abortEarly: false }); // Validate all errors

    if (error) {
        console.error(`[${new Date().toISOString()}] Webhook input validation failed:`, error.details);
        return res.status(400).json({
            error: 'Invalid event payload',
            details: error.details.map(d => d.message)
        });
    }

    // 3. Process Event (asynchronous and error-handled)
    try {
        const processingResult = await processEvent(event); // Await the processing
        console.log(`[${new Date().toISOString()}] Final processing result for ${event.id}:`, processingResult);

        // Send appropriate success response
        if (processingResult.status === 'skipped') {
            res.status(200).json({ status: 'success', message: 'Event already processed, skipped.', result: processingResult });
        } else {
            res.status(200).json({ status: 'success', message: 'Event received and processed.', result: processingResult });
        }
    } catch (error) {
        console.error(`[${new Date().toISOString()}] Error processing webhook event ${event.id}:`, error.message, error.stack);
        // Pass error to Express's generic error handling middleware
        next(error);
    }
});

// --- Generic Error Handling Middleware (MUST be last) ---
app.use((err, req, res, next) => {
    console.error(`[${new Date().toISOString()}] Unhandled error in webhook endpoint:`, err.message, err.stack);
    res.status(500).json({
        error: 'Internal Server Error',
        message: 'An unexpected error occurred during event processing.',
        details: process.env.NODE_ENV === 'development' ? err.message : undefined // Only show details in dev
    });
});

// --- Start Server ---
app.listen(PORT, () => {
    console.log(`[${new Date().toISOString()}] Webhook listener running on port ${PORT}`);
    if (WEBHOOK_SECRET === 'your-super-secret-key') {
        console.warn(`[${new Date().toISOString()}] WARNING: Using default WEBHOOK_SECRET. Please set WEBHOOK_SECRET environment variable.`);
    }
});
```
